@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  body {
    @apply bg-[#0f1115] text-slate-100 font-sans font-light antialiased overflow-x-hidden;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
  }

  /* Standardizing form element weights for better readability */
  input, select, textarea, button {
    @apply font-sans;
  }
}

@layer utilities {
  .scrollbar-hide::-webkit-scrollbar {
    display: none;
  }
  .scrollbar-hide {
    -ms-overflow-style: none;
    scrollbar-width: none;
  }

  /* Custom Animations */
  @keyframes fade-in {
    from { opacity: 0; }
    to { opacity: 1; }
  }

  @keyframes fade-in-up {
    from {
      opacity: 0;
      transform: translateY(20px);
    }
    to {
      opacity: 1;
      transform: translateY(0);
    }
  }

  @keyframes fade-in-left {
    from {
      opacity: 0;
      transform: translateX(-20px);
    }
    to {
      opacity: 1;
      transform: translateX(0);
    }
  }

  @keyframes grid-move {
    0% { transform: perspective(500px) rotateX(60deg) translateY(0); }
    100% { transform: perspective(500px) rotateX(60deg) translateY(40px); }
  }

  @keyframes scan-line {
    0% { top: 0%; opacity: 0; }
    10% { opacity: 0.8; }
    90% { opacity: 0.8; }
    100% { top: 100%; opacity: 0; }
  }

  @keyframes scan {
    0% { transform: translateY(-100%); }
    100% { transform: translateY(1000%); }
  }

  @keyframes pulse-soft {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.7; }
  }

  @keyframes spin-slow {
    from { transform: rotate(0deg); }
    to { transform: rotate(360deg); }
  }

  .animate-fade-in { animation: fade-in 0.6s ease-out forwards; }
  .animate-fade-in-up { animation: fade-in-up 0.8s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
  .animate-fade-in-left { animation: fade-in-left 0.6s ease-out forwards; }
  .animate-grid-move { animation: grid-move 20s linear infinite; }
  .animate-scan-line { animation: scan-line 3s ease-in-out infinite; }
  .animate-scan { animation: scan 2s linear infinite; }
  .animate-pulse-soft { animation: pulse-soft 2s ease-in-out infinite; }
  .animate-spin-slow { animation: spin-slow 8s linear infinite; }
}

.perspective-1000 {
  perspective: 1000px;
}

.path-draw {
  stroke-dasharray: 100;
  stroke-dashoffset: 100;
  animation: draw 2s ease-out forwards;
}

@keyframes draw {
  to { stroke-dashoffset: 0; }
}

import React, { useState, useRef, useEffect } from 'react';
import { Camera, AlertCircle, Loader2, RefreshCw, ImageIcon, Filter, Layers, ScanFace, Check, Cpu, Zap, X, ShieldCheck } from 'lucide-react';
import { analyzeHairstyle, generateHairstylePreview } from '../services/geminiService';
import { VisagismAnalysisResult } from '../types';
import { STYLE_PREFERENCES } from '../constants';

const LOADING_STEPS = [
  "Inicializando rede neural...",
  "Detectando pontos de referência facial...",
  "Mapeando estrutura óssea (Mandíbula/Zigomático)...",
  "Calculando proporções áureas...",
  "Consultando base de dados de visagismo...",
  "Gerando recomendações personalizadas..."
];

export const VisagismFeature: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);

  // Loading State Expanded
  const [loading, setLoading] = useState(false);
  const [loadingStepIndex, setLoadingStepIndex] = useState(0);
  const [loadingProgress, setLoadingProgress] = useState(0);

  const [result, setResult] = useState<VisagismAnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [selectedStyle, setSelectedStyle] = useState<string>("Todos");

  // State for image generation
  const [previewImages, setPreviewImages] = useState<Record<number, string>>({});
  const [loadingPreviews, setLoadingPreviews] = useState<Record<number, boolean>>({});
  const [showOriginal, setShowOriginal] = useState<Record<number, boolean>>({});

  const [fullscreenIndex, setFullscreenIndex] = useState<number | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Enhanced Loading Effect
  useEffect(() => {
    let stepInterval: any;
    let progressInterval: any;

    if (loading) {
      setLoadingStepIndex(0);
      setLoadingProgress(0);

      const totalSteps = LOADING_STEPS.length;
      const stepDuration = 1200; 

      // Step incrementer
      stepInterval = setInterval(() => {
        setLoadingStepIndex((prev) => {
          if (prev < totalSteps - 1) return prev + 1;
          return prev;
        });
      }, stepDuration);

      // Smooth progress bar incrementer with randomness
      progressInterval = setInterval(() => {
        setLoadingProgress((prev) => {
          if (prev >= 99) return 99;
          const increment = Math.random() * 2.5; 
          return prev + increment;
        });
      }, 100);
    }

    return () => {
      clearInterval(stepInterval);
      clearInterval(progressInterval);
    };
  }, [loading]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
      setError("A imagem deve ter no máximo 5MB.");
      return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
      setImage(reader.result as string);
      setResult(null);
      setError(null);
      setPreviewImages({});
      setShowOriginal({});
      setFullscreenIndex(null);
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!image) return;

    setLoading(true);
    setError(null);

    try {
      const analysis = await analyzeHairstyle(image, selectedStyle);
      setLoadingProgress(100); 
      setTimeout(() => {
        setResult(analysis);
        setLoading(false);
      }, 800);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Erro ao analisar a imagem. Verifique a API Key ou tente novamente.");
      setLoading(false);
    }
  };

  const handleGeneratePreview = async (index: number, cutName: string) => {
    if (!image) return;

    setLoadingPreviews(prev => ({ ...prev, [index]: true }));

    try {
      const generatedImage = await generateHairstylePreview(image, cutName);
      setPreviewImages(prev => ({ ...prev, [index]: generatedImage }));
      setShowOriginal(prev => ({ ...prev, [index]: false }));
    } catch (err: any) {
      console.error("Failed to generate preview", err);
      alert(err.message || "Não foi possível gerar a simulação neste momento. (Erro de API/Cota)");
    } finally {
      setLoadingPreviews(prev => ({ ...prev, [index]: false }));
    }
  };

  const toggleBeforeAfter = (index: number) => {
    setShowOriginal(prev => ({ ...prev, [index]: !prev[index] }));
  };

  const handleReset = () => {
    setImage(null);
    setResult(null);
    setError(null);
    setPreviewImages({});
    setLoadingPreviews({});
    setShowOriginal({});
    setFullscreenIndex(null);
    setSelectedStyle("Todos");
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
  };

  return (
    <div id="visagismo" className="max-w-5xl mx-auto py-16 px-6">

      {/* --- ULTRA HUD LOADING OVERLAY --- */}
      {loading && (
        <div className="fixed inset-0 z-[100] bg-[#0f1115] flex flex-col items-center justify-center p-6 overflow-hidden">

          {/* Animated Matrix Grid Background */}
          <div className="absolute inset-0 opacity-20 pointer-events-none perspective-1000">
             <div 
               className="w-full h-[200%] absolute top-[-50%] left-0 bg-[linear-gradient(to_right,#a3e635_1px,transparent_1px),linear-gradient(to_bottom,#a3e635_1px,transparent_1px)] bg-[size:40px_40px] animate-grid-move"
             ></div>
          </div>

          <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-transparent via-lime-400 to-transparent opacity-80 animate-scan-line"></div>

          <div className="relative z-10 w-full max-w-4xl flex flex-col md:flex-row gap-12 items-center justify-center">

            {/* LEFT: Biometric Scanner Visual */}
            <div className="relative w-80 h-80 flex-shrink-0 group">
               {/* Rotating Rings - Multiple Layers */}
               <div className="absolute inset-0 border border-lime-400/20 rounded-full animate-spin-slow"></div>
               <div className="absolute inset-4 border border-lime-400/30 rounded-full border-dashed animate-spin-slow" style={{ animationDirection: 'reverse', animationDuration: '12s' }}></div>
               <div className="absolute inset-0 border-t-2 border-lime-400 rounded-full animate-spin-slow shadow-[0_0_15px_#a3e635]" style={{ animationDuration: '2s' }}></div>

               {/* Face Wireframe Simulation (SVG) with Drawing Animation */}
               <div className="absolute inset-0 flex items-center justify-center p-12 opacity-90">
                  <svg viewBox="0 0 100 100" fill="none" stroke="currentColor" className="w-full h-full text-lime-400 stroke-1 drop-shadow-[0_0_5px_rgba(163,230,53,0.5)]">
                    <path className="path-draw" style={{ animationDelay: '0s' }} d="M20,30 Q50,5 80,30" />
                    <path className="path-draw" style={{ animationDelay: '0.5s' }} d="M20,30 L20,60 Q20,90 50,95 Q80,90 80,60 L80,30" />
                    <path className="path-draw" style={{ animationDelay: '1s' }} d="M35,45 Q50,45 65,45" />
                    <path className="path-draw" style={{ animationDelay: '1.5s' }} d="M48,50 L48,65" />
                    <path className="path-draw" style={{ animationDelay: '1.5s' }} d="M35,75 Q50,80 65,75" />

                    <g className="opacity-30">
                      <path d="M20,40 L80,40" />
                      <path d="M20,50 L80,50" />
                      <path d="M25,60 L75,60" />
                      <path d="M30,70 L70,70" />
                      <path d="M40,20 L40,90" />
                      <path d="M60,20 L60,90" />
                    </g>
                    <rect x="30" y="40" width="40" height="20" className="stroke-lime-300 stroke-[0.5] animate-ping opacity-20" />
                  </svg>
               </div>

               <div className="absolute inset-0 bg-gradient-to-b from-transparent via-lime-400/20 to-transparent h-[10%] w-full animate-scan backdrop-blur-[1px]"></div>

               <div className="absolute top-[28%] left-[25%] w-1.5 h-1.5 bg-lime-400 rounded-full animate-ping"></div>
               <div className="absolute bottom-[35%] right-[30%] w-1.5 h-1.5 bg-lime-400 rounded-full animate-ping" style={{ animationDelay: '0.3s' }}></div>
               <div className="absolute top-[50%] right-[28%] w-1.5 h-1.5 bg-lime-400 rounded-full animate-ping" style={{ animationDelay: '0.7s' }}></div>
               <div className="absolute bottom-[20%] left-[50%] w-1.5 h-1.5 bg-lime-400 rounded-full animate-ping" style={{ animationDelay: '1s' }}></div>
            </div>

            {/* RIGHT: Data Terminal & Progress */}
            <div className="flex-grow w-full max-w-md">
                <div className="mb-8 relative">
                   <h3 className="text-7xl font-display font-normal uppercase tracking-tighter mb-2 text-white relative">
                     <span className="relative z-10">Analisando</span>
                     <span className="absolute top-0 left-0 -ml-1 text-lime-600 opacity-50 animate-pulse">Analisando</span>
                     <span className="animate-pulse text-lime-400">_</span>
                   </h3>
                   <div className="flex justify-between text-lg text-lime-400 font-sans font-medium uppercase tracking-widest mb-3">
                      <span className="flex items-center gap-2"><Cpu className="w-4 h-4 animate-spin-slow" style={{ animationDuration: '3s' }} /> Gemini AI Core</span>
                      <span>Processing...</span>
                   </div>

                   <div className="h-4 w-full bg-[#1c1c1e] rounded-full overflow-hidden border border-white/10 relative">
                      <div className="absolute inset-0 bg-[repeating-linear-gradient(45deg,transparent,transparent_10px,rgba(0,0,0,0.5)_10px,rgba(0,0,0,0.5)_20px)] z-20 opacity-30"></div>
                      <div 
                        className="h-full bg-lime-400 shadow-[0_0_20px_#a3e635] transition-all duration-200 ease-out relative z-10"
                        style={{ width: `${loadingProgress}%` }}
                      >
                         <div className="absolute right-0 top-0 bottom-0 w-1 bg-white animate-pulse"></div>
                      </div>
                   </div>
                   <div className="flex justify-between items-center mt-2">
                      <div className="text-xs font-mono text-slate-500">Mem: {Math.floor(Math.random() * 4000) + 1000}MB / T: {Math.floor(Math.random() * 50) + 30}ms</div>
                      <div className="text-right text-lime-400 font-mono font-medium text-2xl">
                          {Math.floor(loadingProgress)}%
                      </div>
                   </div>
                </div>

                {/* Terminal Log */}
                <div className="bg-black/80 border border-lime-400/20 rounded-xl p-6 font-mono text-sm md:text-base backdrop-blur-md h-52 overflow-hidden relative shadow-[0_0_30px_rgba(0,0,0,0.5)]">
                   <div className="absolute top-0 left-0 w-full h-full bg-[linear-gradient(rgba(163,230,53,0.05)_50%,rgba(0,0,0,0.1)_50%)] bg-[size:100%_4px] pointer-events-none z-0"></div>

                   <div className="flex flex-col gap-3 h-full justify-end pb-2 relative z-10">
                      {LOADING_STEPS.map((step, index) => {
                        const isDone = index < loadingStepIndex;
                        const isCurrent = index === loadingStepIndex;
                        const isPending = index > loadingStepIndex;

                        if (isPending) return null; 

                        return (
                          <div key={index} className="flex items-start gap-3 animate-fade-in-left">
                              <span className="text-slate-600 shrink-0 font-medium">
                                {`0${index + 1}`}
                              </span>
                              <div className="flex-grow">
                                <span className={`${isCurrent ? 'text-lime-400 font-bold drop-shadow-[0_0_5px_rgba(163,230,53,0.8)]' : 'text-slate-400 font-extralight'}`}>
                                  {step}
                                  {isCurrent && <span className="inline-block w-2 h-4 bg-lime-400 ml-1 align-middle animate-pulse"></span>}
                                </span>
                              </div>
                              {isDone && <Check className="w-4 h-4 text-lime-500 mt-0.5" />}
                          </div>
                        );
                      })}
                   </div>
                </div>
            </div>

          </div>
        </div>
      )}

      {/* --- IMAGE FULLSCREEN MODAL --- */}
      {fullscreenIndex !== null && result && (
        <div className="fixed inset-0 z-[200] bg-black/95 backdrop-blur-xl flex flex-col items-center justify-center p-4 animate-fade-in" onClick={() => setFullscreenIndex(null)}>
          <button
            onClick={() => setFullscreenIndex(null)}
            className="absolute top-6 right-6 text-white bg-white/10 hover:bg-white/20 p-4 rounded-full transition-all z-[210]"
          >
            <X className="w-6 h-6" />
          </button>

          <div 
            className="relative w-full max-w-6xl h-full max-h-[90vh] flex flex-col items-center justify-center"
            onClick={(e) => e.stopPropagation()}
          >
              {(() => {
                 const hasGenerated = !!previewImages[fullscreenIndex];
                 const isShowOriginal = showOriginal[fullscreenIndex];
                 const displayImage = (hasGenerated && !isShowOriginal) ? previewImages[fullscreenIndex] : image!;
                 const cut = result.suggestedCuts[fullscreenIndex];

                 return (
                   <>
                     <img
                       src={displayImage}
                       alt={cut.name}
                       className="w-auto h-auto max-w-full max-h-full object-contain rounded-2xl shadow-2xl border border-white/10"
                     />

                     <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-6 bg-[#1c1c1e] px-8 py-5 rounded-full border border-white/10 shadow-2xl">
                        <span className="text-white font-display font-normal tracking-wide text-5xl">{cut.name}</span>
                        <div className="h-6 w-px bg-white/20"></div>

                        {hasGenerated && (
                           <button
                              onClick={() => toggleBeforeAfter(fullscreenIndex)}
                              className="flex items-center gap-2 text-xl font-normal text-lime-400 hover:text-lime-300 transition-colors uppercase tracking-widest font-economica"
                           >
                              <Layers className="w-5 h-5" />
                              {isShowOriginal ? "Ver Simulação" : "Ver Original"}
                           </button>
                        )}
                        {!hasGenerated && (
                           <span className="text-slate-500 text-lg font-sans font-extralight">Simulação não gerada</span>
                        )}
                     </div>
                   </>
                 )
              })()}
          </div>
        </div>
      )}

      <div className="text-center mb-12">
        <h3 className="text-lime-400 font-medium uppercase tracking-widest text-lg mb-3 flex items-center justify-center gap-2 font-sans">
           <Zap className="w-4 h-4 fill-current" /> Feature Premium
        </h3>
        <h2 className="text-7xl md:text-9xl font-display font-normal tracking-tight text-white mb-4">
          Visagismo com IA
        </h2>
        <p className="text-slate-400 max-w-2xl mx-auto text-3xl font-sans font-extralight">
          Análise biométrica avançada para encontrar a geometria perfeita.
        </p>
      </div>

      {/* Upload Section */}
      {!result && (
        <div className="bg-[#1c1c1e] rounded-[32px] p-8 md:p-12 border border-white/5 relative overflow-hidden group hover:border-lime-400/30 transition-all duration-500">

          {!image ? (
            <div 
              className="border-2 border-dashed border-white/10 rounded-[24px] p-16 text-center cursor-pointer hover:border-lime-400 hover:bg-white/5 transition-all duration-300 relative group/upload"
              onClick={() => fileInputRef.current?.click()}
            >
              <div className="w-24 h-24 bg-[#0f1115] rounded-full flex items-center justify-center mx-auto mb-8 group-hover/upload:scale-110 group-hover/upload:bg-lime-400 transition-all duration-300">
                <Camera className="w-10 h-10 text-slate-400 group-hover/upload:text-black transition-colors" />
              </div>
              <h4 className="text-6xl font-display font-normal text-white mb-3">Tire uma selfie ou envie uma foto</h4>
              <p className="text-slate-500 mb-8 font-sans font-extralight text-2xl">Formatos suportados: JPG, PNG (Max 5MB)</p>
              <button className="bg-white text-black px-10 py-4 rounded-full font-normal hover:bg-lime-400 transition-all shadow-lg font-economica text-3xl uppercase tracking-wide">
                Selecionar Arquivo
              </button>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                accept="image/*" 
                className="hidden" 
              />
            </div>
          ) : (
            <div className="flex flex-col items-center animate-fade-in">
              <div className="relative w-64 h-64 mb-8 rounded-[24px] overflow-hidden border-4 border-white/10 shadow-2xl group/img">
                <img src={image} alt="Upload" className="w-full h-full object-cover" />
                <button 
                  onClick={handleReset}
                  className="absolute top-4 right-4 bg-black/60 text-white p-3 rounded-full hover:bg-red-500 transition-colors backdrop-blur-md"
                >
                  <RefreshCw className="w-5 h-5" />
                </button>
              </div>

              {/* Style Preference Filter */}
              <div className="w-full max-w-2xl mb-10">
                  <div className="flex items-center gap-2 mb-4 justify-center text-slate-400 uppercase tracking-widest text-lg font-medium font-sans">
                    <Filter className="w-4 h-4 text-lime-400" />
                    <span>Filtrar Estilo (Opcional)</span>
                  </div>
                  <div className="flex flex-wrap justify-center gap-3">
                    {STYLE_PREFERENCES.map((style) => (
                      <button
                        key={style}
                        onClick={() => setSelectedStyle(style)}
                        className={`
                          px-5 py-2.5 rounded-full text-lg font-medium transition-all duration-300 font-sans
                          ${selectedStyle === style 
                            ? 'bg-lime-400 text-black shadow-lg shadow-lime-400/20 scale-105' 
                            : 'bg-[#2c2c2e] text-slate-300 hover:bg-[#3a3a3c] hover:text-white'
                          }
                        `}
                      >
                        {style}
                      </button>
                    ))}
                  </div>
              </div>

              {error && (
                <div className="bg-red-500/10 border border-red-500/20 text-red-400 px-6 py-4 rounded-xl flex items-center gap-3 mb-8 w-full max-w-md font-sans">
                  <AlertCircle className="w-5 h-5 flex-shrink-0" />
                  <p className="font-medium text-xl">{error}</p>
                </div>
              )}

              <button
                onClick={handleAnalyze}
                disabled={loading}
                className={`
                  w-full max-w-md py-5 px-8 rounded-full font-normal text-3xl flex items-center justify-center gap-4 shadow-xl font-economica uppercase tracking-wide
                  ${loading 
                    ? 'bg-[#2c2c2e] text-slate-500 cursor-not-allowed' 
                    : 'bg-lime-400 text-black hover:bg-lime-300 hover:scale-[1.02] hover:shadow-lime-400/20'
                  } transition-all duration-300
                `}
              >
                  <Cpu className="w-6 h-6" />
                  INICIAR ANÁLISE
              </button>
            </div>
          )}
        </div>
      )}

      {/* Results Section */}
      {result && (
        <div className="animate-fade-in space-y-8">

          {/* Main Result Card */}
          <div className="bg-[#1c1c1e] rounded-[32px] p-8 md:p-12 border border-white/5 flex flex-col md:flex-row gap-10 items-center md:items-start relative overflow-hidden">
             <div className="absolute top-0 right-0 w-[400px] h-[400px] bg-lime-400/5 rounded-full blur-[100px] -translate-y-1/2 translate-x-1/2 pointer-events-none"></div>

            <div className="w-40 h-40 rounded-[32px] border-4 border-[#2c2c2e] flex items-center justify-center bg-[#0f1115] flex-shrink-0 shadow-2xl relative z-10">
               <img src={image!} alt="User" className="w-full h-full object-cover opacity-50 rounded-[28px]" />
               <div className="absolute inset-0 flex items-center justify-center">
                  <ScanFace className="w-12 h-12 text-lime-400" />
               </div>
            </div>

            <div className="text-center md:text-left relative z-10 flex-1">
              <div className="inline-flex items-center gap-2 bg-lime-400/10 px-3 py-1 rounded-full text-lime-400 text-lg font-medium uppercase tracking-wider mb-4 font-sans">
                 <ShieldCheck className="w-4 h-4" />
                 Análise Concluída
              </div>
              <h2 className="text-7xl md:text-8xl font-display font-normal text-white mb-4">
                Formato <span className="text-lime-400">{result.faceShape}</span>
              </h2>
              <div className="flex flex-col gap-4">
                 <p className="text-slate-400 text-2xl md:text-3xl leading-relaxed max-w-2xl font-sans font-extralight">
                  Para este formato, a IA selecionou estilos que harmonizam a geometria facial, 
                  valorizando seus pontos fortes.
                </p>
              </div>
            </div>

            <div className="md:ml-auto relative z-10 self-center md:self-start">
               <button 
                onClick={handleReset} 
                className="px-8 py-3 rounded-full bg-[#2c2c2e] hover:bg-[#3a3a3c] text-white text-2xl font-normal transition-all font-economica uppercase tracking-wide"
              >
                Nova Análise
              </button>
            </div>
          </div>

          {/* Cuts Grid */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {result.suggestedCuts.map((cut, index) => {
              const hasGenerated = !!previewImages[index];
              const isShowOriginal = showOriginal[index];
              const isLoadingThis = loadingPreviews[index];
              const displayImage = (hasGenerated && !isShowOriginal) ? previewImages[index] : image!;

              return (
              <div 
                key={index} 
                className="bg-[#1c1c1e] rounded-[32px] overflow-hidden hover:bg-[#252527] transition-all duration-300 group flex flex-col hover:shadow-2xl border border-transparent hover:border-white/5"
              >
                {/* Image Area */}
                <div className="relative w-full aspect-[4/5] bg-black flex items-center justify-center overflow-hidden">

                  {isLoadingThis ? (
